// // This module implements a 4-bit binary counter with asynchronous reset. The counter decrements its value on the falling edge of the clock. If the reset signal is low, the counter is reset to 15.
module binary_counter(clk, reset, count);

    input clk;
    input reset;
    output [3:0] count;
    reg [3:0] count;
    initial count = 0;

    always @(posedge clk)
        begin
            if (reset)
                count <= 0;
            else
                count <= count + 1;
        end

endmodule
